def is_prime(n):
    """Check if a number is prime."""
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    # Check odd divisors up to sqrt(n)
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

def find_nth_prime(n):
    """Find the nth prime number."""
    if n <= 0:
        return None
    count = 0
    candidate = 1
    while count < n:
        candidate += 1
        if is_prime(candidate):
            count += 1
            print(f"Prime #{count}: {candidate}")
    return candidate

if __name__ == "__main__":
    target = 17
    result = find_nth_prime(target)
    print(f"\nThe {target}th prime number is: {result}")
